package io.spdigital.ubm.admin.service.impl;

import io.spdigital.ubm.util.MaskingUtil;
import io.spdigital.ubm.admin.dto.ForgotPassword;
import io.spdigital.ubm.admin.service.UserService;
import io.spdigital.ubm.config.ConnectionProperties;
import io.spdigital.ubm.config.connector.ReactiveConnector;
import io.spdigital.ubm.exception.UbmApiException;
import io.spdigital.ubm.model.dto.BaseResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;
import org.springframework.stereotype.Service;
import reactor.core.publisher.Mono;

import java.util.Arrays;
import java.util.Collections;
import java.util.Map;
import java.util.Objects;

import static io.spdigital.ubm.admin.common.ErrorCodes.UBM_FORGOT_PASSWORD_ERROR_CODE;
import static io.spdigital.ubm.admin.common.ErrorCodes.UBM_FORGOT_PASSWORD_ERROR_MSG;

@Slf4j
@Service
@RequiredArgsConstructor
public class UserServiceImpl implements UserService {

	private final ReactiveConnector reactiveConnector;

	@Override
	public Mono<BaseResponse> forgotPassword(String email) {
		if (StringUtils.isEmpty(email)) {
			return Mono.error(new UbmApiException(UBM_FORGOT_PASSWORD_ERROR_MSG, UBM_FORGOT_PASSWORD_ERROR_CODE,
					"Email cannot be empty"));
		}

		return Mono.just(email)
			.flatMap(mail -> reactiveConnector.reactiveGet(ConnectionProperties.Host.PROFILEAPI, ForgotPassword.URL,
					Map.of("username", Arrays.asList(mail)), Collections.emptyMap(), ForgotPassword.Response.class))
			.doOnError(throwable -> log.error("forgotPassword failed :: email:{} :: Message:{}",
					MaskingUtil.maskEmail(email), throwable.getMessage()))
			.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_FORGOT_PASSWORD_ERROR_MSG,
					UBM_FORGOT_PASSWORD_ERROR_CODE, "Failed to send forgot password email")))
			.filter(Objects::nonNull)
			.thenReturn(BaseResponse.success());
	}

}

