package io.spdigital.ubm.util;

import jakarta.xml.bind.DatatypeConverter;
import lombok.extern.slf4j.Slf4j;
import org.springframework.core.io.buffer.DataBufferUtils;
import org.springframework.http.codec.multipart.FilePart;
import org.springframework.stereotype.Component;
import reactor.core.publisher.Mono;

import java.nio.charset.StandardCharsets;

@Slf4j
@Component
public class FileUtil {

	public Mono<String> getFileByteArray(FilePart filePart) {

		return DataBufferUtils.join(filePart.content()).map(dataBuffer -> {
			byte[] bytes = new byte[dataBuffer.readableByteCount()];
			dataBuffer.read(bytes);
			DataBufferUtils.release(dataBuffer);
			return bytes;
		}).map(DatatypeConverter::printBase64Binary);
	}

	public Mono<String> getFileToString(FilePart filePart) {
		return DataBufferUtils.join(filePart.content()).map(dataBuffer -> {
			byte[] bytes = new byte[dataBuffer.readableByteCount()];
			dataBuffer.read(bytes);
			DataBufferUtils.release(dataBuffer);
			return bytes;
		}).map(bytes -> new String(bytes, StandardCharsets.UTF_8));
	}

}

package io.spdigital.ubm.config;

import lombok.RequiredArgsConstructor;
