import java.util.List;

public interface Holidays {

	String DATE_FORMAT = "yyyy-MM-dd";

	@Data
	@JsonInclude(JsonInclude.Include.NON_NULL)
	class HolidayInfoDTO {

		private List<Holiday> publicHolidayInfo;

