		switch (host) {
			case SAPPO:
				return this.sap;
			case SWITCHEROO:
				return this.switcheroo;
			case AUDIT:
				return this.audit;
			case SKALBOX:
				return this.skalbox;
			case SKALBOX_M2M:
				return this.skalbox_m2m;
			case YGGDRASIL:
				return this.yggdrasil;
			case YGGDRASIL_M2M:
