	@Override
	public Mono<SearchCustomers.Response> getCustomers(String type, String searchString, Integer pageNumber,
			Integer pageSize, String direction) {
		// if type is accountNo then search BpNo then SearchCustomer with BpNo
		if (type.equals(ACCOUNT_NO)) {
			return getUtilityAccount(searchString).flatMap(bpNo -> {
				if (StringUtils.isBlank(bpNo)) {
					return Mono.just(SearchCustomers.Response.builder()
						.total(0L)
						.customerProfiles(Collections.emptyList())
						.build());
				}
				return reactiveConnector
					.reactivePost(YGGDRASIL, Yggdrasil.SEARCH_CUSTOMERS_ENDPOINT, SearchCustomers.Request.builder()
						.direction(direction)
						.pageSize(pageSize)
						.pageNumber(pageNumber)
						.sortBy(CREATED_AT)
						.filterParams(Map.of(BP_NO, List.of(bpNo), PROFILE_STATUS,
								List.of(PROFILE_STATUS_ACTIVE, PROFILE_STATUS_DELETE, PROFILE_STATUS_IN_PROGRESS)))
						.build(), SearchCustomers.Response.class)
					.doOnError(throwable -> log.error(ERROR_OCCURRED, throwable.getMessage()))
					.onErrorResume(ex -> Mono
						.error(new UbmApiException(UBM_GET_CUSTOMERS_ERROR_MSG, UBM_GET_CUSTOMERS_ERROR_CODE,
								String.format("Type :%s, SearchString :%s", type, searchString))));
			});
		}
		// otherwise SearchCustomer with type and searchString
		return reactiveConnector
			.reactivePost(YGGDRASIL, Yggdrasil.SEARCH_CUSTOMERS_ENDPOINT,
					SearchCustomers.Request.builder()
						.direction(direction)
						.pageSize(pageSize)
						.pageNumber(pageNumber)
						.sortBy(CREATED_AT)
						.filterParams(Map.of(type, List.of(searchString), PROFILE_STATUS,
								List.of(PROFILE_STATUS_ACTIVE, PROFILE_STATUS_DELETE, PROFILE_STATUS_IN_PROGRESS)))
						.build(),
					SearchCustomers.Response.class)
			.doOnError(throwable -> log.error(ERROR_OCCURRED, throwable.getMessage()))
			.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_GET_CUSTOMERS_ERROR_MSG,
					UBM_GET_CUSTOMERS_ERROR_CODE, String.format("Type :%s, SearchString :%s", type, searchString))));
	}

	private Mono<String> getUtilityAccount(final String accountNo) {
		return reactiveConnector
			.reactivePost(YGGDRASIL_M2M, GQL_ENDPOINT,
					new GraphQLQuery(UTILITIES_BY_ACCOUNT_QUERY, Map.of(ACCOUNT_NO, accountNo, ELECT_SCHEME, false)),
					Utility.Response.class)
			.filter(utility -> validateUtilityAccounts(utility))
			.flatMap(accountUtility -> validateUtilityStatusAndIamId(accountUtility) ? Mono.just(accountUtility)
					: reactiveConnector.reactivePost(YGGDRASIL_M2M, GQL_ENDPOINT,
							new GraphQLQuery(UTILITIES_BY_ACCOUNT_QUERY,
									Map.of(ACCOUNT_NO,
											AccountUtility.checkIsMSSLAccount(accountNo)
													? accountUtility.getData()
														.getUtilitiesByAccountNoM2M()
														.getAccounts()
														.get(0)
														.getEbsAccountNo()
													: accountUtility.getData()
														.getUtilitiesByAccountNoM2M()
														.getAccounts()
														.get(0)
														.getMsslAccountNo(),
											ELECT_SCHEME, false)),
							Utility.Response.class))
			.filter(res -> Objects.nonNull(res.getData()) && Objects.nonNull(res.getData().getUtilitiesByAccountNoM2M())
					&& Objects.nonNull(res.getData().getUtilitiesByAccountNoM2M().getAccounts())
					&& !res.getData().getUtilitiesByAccountNoM2M().getAccounts().isEmpty())
			.map(utilResp -> utilResp.getData().getUtilitiesByAccountNoM2M().getAccounts().get(0).getBpNo())
			.switchIfEmpty(Mono.just(""));
	}

	private boolean validateUtilityAccounts(Utility.Response utility) {
		return Objects.nonNull(utility) && Objects.nonNull(utility.getData())
				&& Objects.nonNull(utility.getData().getUtilitiesByAccountNoM2M())
				&& Objects.nonNull(utility.getData().getUtilitiesByAccountNoM2M().getAccounts())
				&& !utility.getData().getUtilitiesByAccountNoM2M().getAccounts().isEmpty();
	}

	private boolean validateUtilityStatusAndIamId(Utility.Response utility) {
		return Objects.nonNull(utility) && Objects.nonNull(utility.getData())
				&& Objects.nonNull(utility.getData().getUtilitiesByAccountNoM2M())
				&& utility.getData().getUtilitiesByAccountNoM2M().getStatus().equalsIgnoreCase(SUCCESS)
				&& Objects.nonNull(utility.getData().getUtilitiesByAccountNoM2M().getIamId());
	}

	@Override
	public Mono<GetCustomerResponse> getCustomer(String bpNo, String userId) {
		return reactiveConnector
			.reactivePost(YGGDRASIL, GET_BP_MAPPING_BY_USERID_AND_BPNO,
					Yggdrasil.User.Request.builder().userId(userId).bpNo(bpNo).build(), Yggdrasil.User.BPMapping.class)
			.filter(Objects::nonNull)
			.flatMap(bpMapping -> {
				Mono<EAccountDetail> eAccountDetailsMono = getEAccountDetails(userId, bpMapping);
				Mono<UtilityAccountDetail> utilityAccountDetailsMono = getUtilityAccDetails(bpNo, bpMapping);
				Mono<ProfileApiDetails> profileApiMono = eAccountDetailsMono
					.flatMap(eAccountDetail -> getProfileApiDetails(eAccountDetail.getIamUser().getIamUserId()));
				return Mono.zip(eAccountDetailsMono, utilityAccountDetailsMono, profileApiMono)
					.map(data -> GetCustomerResponse.builder()
						.accountDetail(data.getT1())
						.utilityAccountDetail(data.getT2())
						.profileApiDetails(data.getT3())
						.build());
			})
			.switchIfEmpty(Mono.error(new UbmApiException(UBM_GET_CUSTOMER_BP_EMPTY_ERROR_MSG,
					UBM_GET_CUSTOMER_BP_EMPTY_ERROR_CODE, String.format(BP_NO_S_USER_ID_S, bpNo, userId))))
			.doOnError(throwable -> log.error(ERROR_OCCURRED, throwable.getMessage()))
			.onErrorResume(ex -> {
				// this if-clause is to return error if customer bpmapping is empty ->
				// UBM_GET_CUSTOMER_BP_EMPTY_ERROR_CODE
				if (ex instanceof UbmApiException
						&& ((UbmApiException) ex).getCode().equals(UBM_GET_CUSTOMER_BP_EMPTY_ERROR_CODE)) {
					return Mono.error(ex);
				}
				return Mono.error(new UbmApiException(UBM_GET_CUSTOMER_ERROR_MSG, UBM_GET_CUSTOMER_ERROR_CODE,
						String.format(BP_NO_S_USER_ID_S, bpNo, userId)));
			});
	}

	private Mono<ProfileApiDetails> getProfileApiDetails(String iamId) {
		return reactiveConnector
			.reactiveGet(PROFILEAPI, M2M_SEARCH_USERS, Map.of("iam_ids", List.of(iamId)), Collections.emptyMap(),
					ProfileApi.GetScopes.Response.class)
			.map(userProfileScope -> ProfileApiDetails.builder()
				.mobileNo(userProfileScope.getUsers().get(0).getUserMetadata().getNumber())
				.build())
			.doOnError(error -> log.error("#reviewApplication :: getScopes  error:: {} :: iamId {}", error.getMessage(),
					iamId))
			.onErrorResume(
					ex -> Mono.error(new UbmApiException(UBM_GET_SCOPE_ERROR_MSG, UBM_GET_SCOPE_ERROR_CODE, iamId)))
			.switchIfEmpty(
					Mono.error(new UbmApiException(UBM_GET_PROFILE_USER_ERROR_MSG, UBM_GET_SCOPE_ERROR_CODE, iamId)));
	}

	public Mono<EAccountDetail> getEAccountDetails(String userId, Yggdrasil.User.BPMapping bpMapping) {
		// we are re-using yggdrasil dto & api
		// so have to parse to request body
		return
		// get Customer Profile
		reactiveConnector
			.reactivePost(YGGDRASIL, GET_CP_BY_USER_ID_WITH_IAM,
					Yggdrasil.User.Request.builder().userId(userId).build(), Yggdrasil.User.YD.Detail.class)
			// merge response
			.map(yggDetail -> EAccountDetail.builder()
				.bpNo(yggDetail.getBpNo())
				.createdBy(yggDetail.getCreatedBy())
				.createdDate(yggDetail.getCreatedDate())
				.email(yggDetail.getEmail())
				// deleted status doesn't have Iam
				.iamUser(Objects.nonNull(yggDetail.getIam()) ? GetCustomerResponse.IamUser.builder()
					.iamUserId(yggDetail.getIam().getIamId())
					.createdDate(yggDetail.getIam().getCreatedDate())
					.build() : null)
				.userId(yggDetail.getUserId())
				.isCompany(yggDetail.getIsCompany())
				.changePassword(yggDetail.getChangePassword())
				.modifiedBy(yggDetail.getModifiedBy())
				.modifiedDate(yggDetail.getModifiedDate())
				.name(yggDetail.getName())
				.nric(MaskingUtil.maskNricOrUen(yggDetail.getNric()))
				.uen(yggDetail.getUen())
				.approvalFlag(yggDetail.getApprovalFlag())
				.sapSystem(bpMapping.getSystem())
				.profileStatus(yggDetail.getProfileStatus())
				.contactConsentDate(String.valueOf(yggDetail.getConsentDate()))
				.build())
			.doOnError(ex -> log.error(
					"[UbmServiceImpl] :: getCustomerProfile :: error occurred :: exception: {}, userId: {}",
					ex.getMessage(), userId))
			.onErrorMap(ex -> new UbmApiException(UBM_GET_E_ACC_DETAILS_ERROR_MSG, UBM_GET_E_ACC_DETAILS_ERROR_CODE,
					"userId: " + userId));
	}

	public Mono<UtilityAccountDetail> getUtilityAccDetails(String bpNo, Yggdrasil.User.BPMapping bpMapping) {
		// retrieve system type
		return Mono.just(bpMapping)
			.filter(system -> bpMapping.getSystem().equals(System.MSSL.getSymbol()))
			// if MSSL then retrieve via corresponding ebs accNo in MSSL response
			.flatMap(mssl -> sapService
				.reactivePost(SAP.MSSL_CUSTOMER_DETAILS_RETRIEVAL, SAP.Request.builder().bpNo(bpNo).build(),
						MsslResponse.class)
				.map(MsslResponse::getHolder)
				.flatMap(msslBpItems -> {
					if (msslBpItems.getBpItems() != null && !msslBpItems.getBpItems().isEmpty()) {
						return Mono.just(msslBpItems.getBpItems().get(0));
					}
					else {
						return Mono.empty();
					}
				})
				.flatMap(msslBpItem -> sapService
					.reactivePost(SAP.EBS_CUSTOMER_DETAILS_RETRIEVAL, SAP.withAccountNo(msslBpItem.getEbsAccountNo()),
							SAP.EbsResponse.class)
					.map(SAP.EbsResponse::getDetailsHolder)
					.flatMap(AdminServiceImpl::getBpItem)))
			// if EBS then retrieve data from SAP immediately
			.switchIfEmpty(sapService.reactivePost(SAP.CUSTOMER_PROFILE_RETRIEVAL,
					SAP.RequestOld.builder().bpNo(bpNo).build(), SAP.EbsResponse.BpItem.class))
			.flatMap(ebsBpItem -> reactiveConnector
				.reactivePost(YGGDRASIL, GET_USER_BY_BP_NO,
						Yggdrasil.User.Request.builder()
							.bpNos(List.of(ebsBpItem.getBpNo() != null ? ebsBpItem.getBpNo() : bpNo))
							.build(),
						Yggdrasil.User.YD.Detail[].class)
				.map(userArray -> {
					Optional<Yggdrasil.User.YD.Detail> targetUser = Arrays.stream(userArray)
						.filter(u -> u.getEmail() != null && u.getEmail().equals(ebsBpItem.getEmailAddress()))
						.findFirst();

					String profileMobile = targetUser.map(Yggdrasil.User.YD.Detail::getMobile)
						.filter(m -> !m.isEmpty())
						.orElse(ebsBpItem.getMobileNo());
					return buildUtilityAccountDetail(ebsBpItem, profileMobile);
				})
				.switchIfEmpty(Mono.fromSupplier(() -> buildUtilityAccountDetail(ebsBpItem, ebsBpItem.getMobileNo()))))
			.switchIfEmpty(Mono.just(UtilityAccountDetail.builder().build()))
			.doOnError(throwable -> log.error(ERROR_OCCURRED, throwable.getMessage()))
			.onErrorResume(ex -> Mono
				.error(new UbmApiException(GENERIC_ERROR_MSG, GENERIC_ERROR_CODE, String.format("BpNo :%s", bpNo))));
	}

	private UtilityAccountDetail buildUtilityAccountDetail(SAP.EbsResponse.BpItem ebsBpItem, String mobile) {
		return UtilityAccountDetail.builder()
			.bpName(ebsBpItem.getBpName())
			.premiseAddress(ebsBpItem.getPremiseAddress())
			.emailSAP(ebsBpItem.getEmailAddress())
			.mobile(mobile)
			.phone(ebsBpItem.getPhone())
			.build();
	}

	private static Mono<SAP.EbsResponse.BpItem> getBpItem(SAP.EbsResponse.DetailsHolder bpItems) {
		if (bpItems.getBpItems() != null && !bpItems.getBpItems().isEmpty()) {
			return Mono.just(bpItems.getBpItems().get(0));
		}
		else {
			return Mono.empty();
		}
	}

