public interface Holidays {

	String DATE_FORMAT = "yyyy-MM-dd";

	@Data
	@JsonInclude(JsonInclude.Include.NON_NULL)
	class HolidayInfoDTO {

		private List<Holiday> publicHolidayInfo;

		private List<Holiday> specialHolidayInfo;

		private List<AppointmentSlotConfig> apptSlotConfigOpenAcc;

		private List<AppointmentSlotConfig> apptSlotConfigCloseAcc;

	}

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	@JsonInclude(JsonInclude.Include.NON_NULL)
	class Holiday {

		private Long id;

		private String description;

		@JsonFormat(shape = JsonFormat.Shape.STRING, pattern = DATE_FORMAT)
		private LocalDate date;

		public static Holiday from(PublicHolidayEntity entity) {
			return Holiday.builder()
				.id(entity.getId())
				.date(entity.getDate().toLocalDate())
				.description(entity.getDescription())
				.build();
		}

		public static Holiday from(SpecialHolidayEntity entity) {
			return Holiday.builder()
				.id(entity.getId())
				.date(entity.getDate().toLocalDate())
				.description(entity.getDescription())
				.build();
		}

	}

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	@JsonInclude(JsonInclude.Include.NON_NULL)
	class AppointmentSlotConfig {

		private Long id;

		@JsonFormat(shape = JsonFormat.Shape.STRING, pattern = DATE_FORMAT)
		private LocalDate unavailFrom;

		@JsonFormat(shape = JsonFormat.Shape.STRING, pattern = DATE_FORMAT)
		private LocalDate unavailTo;

		private String message;

		private String modifiedBy;

		@JsonFormat(shape = JsonFormat.Shape.STRING, pattern = DATE_FORMAT)
		private LocalDate modifiedDate;

		private AppointmentSlotConfigType type;

		public static AppointmentSlotConfig from(AppointmentSlotConfigEntity entity) {
			return AppointmentSlotConfig.builder()
				.id(entity.getId())
				.unavailFrom(entity.getUnavailFrom().toLocalDate())
				.unavailTo(entity.getUnavailTo().toLocalDate())
				.message(entity.getMessage())
				.modifiedBy(entity.getModifiedBy())
				.modifiedDate(entity.getModifiedDate().toLocalDate())
				.type(AppointmentSlotConfigType.fromValue(entity.getType()))
				.build();
		}

	}

	@RequiredArgsConstructor
	@Getter
	enum AppointmentSlotConfigType {

		ACCOUNT_OPENING(1), ACCOUNT_CLOSING(2);

		@JsonValue
		private final int value;

		@JsonCreator
		public static AppointmentSlotConfigType fromValue(int value) {
			for (AppointmentSlotConfigType e : values()) {
				if (e.getValue() == value) {
					return e;
				}
			}
			throw new ServerException("Invalid enum value: " + value);
		}

	}

