package io.spdigital.ubm.service.holidays;

import io.spdigital.ubm.data.jpa.entity.AppointmentSlotConfigEntity;
import io.spdigital.ubm.data.jpa.entity.PublicHolidayEntity;
import io.spdigital.ubm.data.jpa.entity.SpecialHolidayEntity;
import io.spdigital.ubm.data.jpa.repository.AppointmentSlotConfigRepository;
import io.spdigital.ubm.data.jpa.repository.PublicHolidayRepository;
import io.spdigital.ubm.data.jpa.repository.SpecialHolidayRepository;
import io.spdigital.ubm.model.dto.BaseResponse;
import io.spdigital.ubm.service.holidays.dto.Holidays;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.util.CollectionUtils;
import java.time.LocalDate;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class HolidaysServiceImpl implements HolidaysService {

	private final PublicHolidayRepository publicHolidayRepository;

	private final SpecialHolidayRepository specialHolidayRepository;

	private final AppointmentSlotConfigRepository appointmentSlotConfigRepository;

	@Override
	public BaseResponse createHolidays(Holidays.HolidaySaving holidaySavingDto) {
		log.info("Create Holidays Start");

		if (!CollectionUtils.isEmpty(holidaySavingDto.getPublicHolidays())) {
			holidaySavingDto.getPublicHolidays()
				.stream()
				.map(PublicHolidayEntity::from)
				.forEach(publicHolidayRepository::save);
		}
		if (!CollectionUtils.isEmpty(holidaySavingDto.getSpecialHolidays())) {
			holidaySavingDto.getSpecialHolidays()
				.stream()
				.map(SpecialHolidayEntity::from)
				.forEach(specialHolidayRepository::save);
		}
		if (!CollectionUtils.isEmpty(holidaySavingDto.getApptSlotsConfig())) {
			holidaySavingDto.getApptSlotsConfig()
				.stream()
				.map(AppointmentSlotConfigEntity::from)
				.forEach(appointmentSlotConfigRepository::save);
		}

		log.info("Create Holidays End");
		return BaseResponse.success();
	}

	@Override
	public Holidays.HolidayInfoDTO getHolidays() {
		log.info("Get Holidays Start");

		Holidays.HolidayInfoDTO holidayInformation = new Holidays.HolidayInfoDTO();
		holidayInformation.setPublicHolidayInfo(getPublicHolidays());
		holidayInformation.setSpecialHolidayInfo(getSpecialHolidays());
		Map<Holidays.AppointmentSlotConfigType, List<Holidays.AppointmentSlotConfig>> apptSlotConfigMap = getApptSlotConfigListAccToType(
				getApptSlotsConfig());
		holidayInformation
			.setApptSlotConfigOpenAcc(apptSlotConfigMap.get(Holidays.AppointmentSlotConfigType.ACCOUNT_OPENING));
		holidayInformation
			.setApptSlotConfigCloseAcc(apptSlotConfigMap.get(Holidays.AppointmentSlotConfigType.ACCOUNT_CLOSING));

		log.info("Get Holidays End");
		return holidayInformation;
	}

	@Override
	public BaseResponse deleteHolidays(Holidays.HolidayDeletion holidayDeletionIds) {
		log.info("Delete Holidays Start");

		if (!CollectionUtils.isEmpty(holidayDeletionIds.getPublicHolidayIds())) {
			publicHolidayRepository.deleteAllById(holidayDeletionIds.getPublicHolidayIds());
			log.debug("Deleted public holiday information.");
		}

		if (!CollectionUtils.isEmpty(holidayDeletionIds.getSpecialHolidayIds())) {
			specialHolidayRepository.deleteAllById(holidayDeletionIds.getSpecialHolidayIds());
			log.debug("Deleted special holiday information.");
		}

		if (!CollectionUtils.isEmpty(holidayDeletionIds.getApptSlotConfigIds())) {
			appointmentSlotConfigRepository.deleteAllById(holidayDeletionIds.getApptSlotConfigIds());
			log.debug("Deleted appointment slot config information.");
		}

		log.info("Delete Holidays End");
		return BaseResponse.success();
	}

	private List<Holidays.Holiday> getPublicHolidays() {
		return publicHolidayRepository.findByDateGreaterThanOderByDate(LocalDate.now().atStartOfDay())
			.stream()
			.map(Holidays.Holiday::from)
			.toList();
	}

	private List<Holidays.Holiday> getSpecialHolidays() {
		return specialHolidayRepository.findByDateGreaterThanOderByDate(LocalDate.now().atStartOfDay())
			.stream()
			.map(Holidays.Holiday::from)
			.toList();
	}

	public List<Holidays.AppointmentSlotConfig> getApptSlotsConfig() {
		return appointmentSlotConfigRepository
			.findByUnavailToGreaterThanOderByUnavailFrom(LocalDate.now().atStartOfDay())
			.stream()
			.map(Holidays.AppointmentSlotConfig::from)
			.toList();
	}

	private Map<Holidays.AppointmentSlotConfigType, List<Holidays.AppointmentSlotConfig>> getApptSlotConfigListAccToType(
			List<Holidays.AppointmentSlotConfig> apptSlotsConfig) {
		return apptSlotsConfig.stream().collect(Collectors.groupingBy(Holidays.AppointmentSlotConfig::getType));
	}

}

package io.spdigital.ubm.common.enums;

import lombok.Getter;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpMethod;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.web.util.pattern.PathPatternParser;

import java.util.List;

@RequiredArgsConstructor
@Getter
public enum SkipURLPermission {

	ACTUATOR_HEALTH(List.of("/", "/actuator/health"), HttpMethod.GET), PUBLIC_URLS(List.of("/public/**"), null);

	private final List<String> uris; // List of allow uris

	private final HttpMethod method; // method null will allow all http method

	private static final PathPatternParser PARSER = new PathPatternParser();

	public boolean permissionMatches(ServerHttpRequest request) {
		return uris.stream().anyMatch(uri -> PARSER.parse(uri).matches(request.getPath().pathWithinApplication()))
				&& (method == null || request.getMethod() == method);
	}

}

