				.port(Integer.parseInt(proxyProps.getPort()))
				.nonProxyHosts(proxyProps.getBypass()))
			.secure(t -> t.sslContext(sslContext).handshakeTimeout(Duration.ofMinutes(1)));
		return WebClient.builder()
			.codecs(clientCodecConfigurer -> clientCodecConfigurer.defaultCodecs().maxInMemorySize(CODEC_20_MB_SIZE))
			.clientConnector(new ReactorClientHttpConnector(httpClient));
	}

	@Bean
	public WebClient webClient(WebClient.Builder builder) {
		return builder.filters(functions -> {
			functions.add(logRequest());
			functions.add(logResponse());
		}).build();
	}

	private ExchangeFilterFunction logRequest() {
		return ExchangeFilterFunction.ofRequestProcessor(req -> {
			StringBuilder msg = new StringBuilder("Request:\n");
			req.headers().forEach((key, val) -> msg.append(key + ": " + val + "\n"));
			log.debug(msg.toString());
			return Mono.just(req);
		});
	}

	private ExchangeFilterFunction logResponse() {
		return ExchangeFilterFunction.ofResponseProcessor(res -> {
			StringBuilder msg = new StringBuilder("Response:\n");
			res.headers().asHttpHeaders().forEach((key, val) -> msg.append(key + ": " + val + "\n"));
			log.debug(msg.toString());
			return Mono.just(res);
		});
	}

	@Configuration
	public static class SSLConfiguration {

		@Bean
		public SslContext sslContext() throws SSLException {
			return SslContextBuilder.forClient().trustManager(InsecureTrustManagerFactory.INSTANCE).build();
		}

	}

}

