package io.spdigital.ubm.logging;

import org.aspectj.lang.ProceedingJoinPoint;
import org.aspectj.lang.Signature;
import org.aspectj.lang.annotation.Around;
import org.aspectj.lang.annotation.Aspect;
import org.aspectj.lang.reflect.MethodSignature;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.aop.support.AopUtils;
import org.springframework.stereotype.Component;
import reactor.core.publisher.Mono;

import java.time.Duration;
import java.time.Instant;
import java.util.Objects;

@Aspect
@Component
public class LoggableAspect {

	@Around("@annotation(Loggable)")
	public Object loggable(ProceedingJoinPoint joinPoint) throws Throwable {

		final Instant start = Instant.now();

		// log fields
		Class<?> category = AopUtils.getTargetClass(joinPoint.getTarget());
		Logger log = LoggerFactory.getLogger(category);
		Signature methodSig = joinPoint.getSignature();
		String methodName = ((MethodSignature) joinPoint.getSignature()).getMethod().getName();

		// execute
		Object pointcutObject = null;

		try {
			// populate MDC
			MDC.put("mdc.class", methodSig.toString());
			MDC.put("mdc.method", methodName);
			log.info("[MethodCall]({}[{}]): Calling({})", methodName, methodSig, joinPoint.getArgs());
			pointcutObject = joinPoint.proceed();
		}
		catch (Throwable e) {
			log.error("[MethodCall]({}[{}]): Request({}) Exception caused by ", methodName, methodSig,
					joinPoint.getArgs(), e);
			throw e;
		}
		finally {
			// get the execution time
			long executionTime = getExecutionTime(start);

			MDC.put("mdc.duration", String.valueOf(executionTime));
			if (pointcutObject instanceof Mono) {
				var result = (Mono) pointcutObject;
				return result.doOnSuccess(o -> {
					if (Objects.nonNull(o)) {
						log.info("[Reactive MethodCall]({}[{}]) Request({}) Returned({}) in {}ms", methodName,
								methodSig, joinPoint.getArgs(), o.toString(), executionTime);
					}
				});
			}
			else {
				log.info("[MethodCall]({}[{}]) Request({}) Returned({}) in {}ms", methodName, methodSig, pointcutObject,
						joinPoint.getArgs(), executionTime);
			}

			// clear MDC context
			MDC.clear();
		}

		return pointcutObject;
	}

	@Around("@annotation(PORequest)")
	public Object poRequest(ProceedingJoinPoint joinPoint) throws Throwable {

		// start timer
		Class<?> category = AopUtils.getTargetClass(joinPoint.getTarget());
		Logger log = LoggerFactory.getLogger(category);
		Instant start = Instant.now();

		// execute
		Object pointcutObject = null;

		try {
			MDC.put("mdc.method", "PO Request");
			pointcutObject = joinPoint.proceed();
		}
		catch (Throwable e) {
			log.error("[PO-Request]({}): Exception caused by ", joinPoint.getArgs(), e);
			throw e;
		}
		finally {
			// get the execution time
			long executionTime = getExecutionTime(start);

			MDC.put("mdc.duration", String.valueOf(executionTime));
			if (pointcutObject instanceof Mono) {
				var result = (Mono) pointcutObject;
				return result.doOnSuccess(o -> {
					if (Objects.nonNull(o)) {
						log.info("[Reactive PO-Request]({}): response({}) in {}ms", joinPoint.getArgs(), o.toString(),
								executionTime);
					}
				});
			}
			else {
				log.info("[PO-Request]({}): response({}) in {}ms", joinPoint.getArgs(), pointcutObject, executionTime);
			}

			// clear MDC context
			MDC.clear();
		}

		return pointcutObject;
	}

	private long getExecutionTime(Instant start) {
		Instant finish = Instant.now();
		return Duration.between(start, finish).toMillis();
	}

}

