package io.spdigital.ubm.config;

import tools.jackson.core.JacksonException;
import tools.jackson.databind.ObjectMapper;
import io.spdigital.ubm.common.UserUtil;
import io.spdigital.ubm.common.enums.Permission;
import io.spdigital.ubm.common.enums.SkipURLPermission;
import io.spdigital.ubm.exception.ServerException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.http.server.reactive.ServerHttpResponse;
import io.spdigital.ubm.common.SecurityContextHeader;
import org.springframework.stereotype.Component;
import org.springframework.web.server.ServerWebExchange;
import org.springframework.web.server.WebFilter;
import org.springframework.web.server.WebFilterChain;
import org.springframework.web.util.pattern.PathPatternParser;
import reactor.core.publisher.Mono;
import java.util.Arrays;
import java.util.Base64;

@Slf4j
@Component
@RequiredArgsConstructor
public class PermissionFilter implements WebFilter {

	private static final PathPatternParser PARSER = new PathPatternParser();

	@Override
	public Mono<Void> filter(ServerWebExchange exchange, WebFilterChain chain) {
		try {
			ServerHttpRequest request = exchange.getRequest();

			boolean isSkipURI = Arrays.stream(SkipURLPermission.values())
				.anyMatch(skipURLPermission -> skipURLPermission.permissionMatches(request));
			if (isSkipURI) {
				return chain.filter(exchange);
			}

			boolean isAllowURI = Arrays.stream(Permission.values())
				.noneMatch(permission -> permission.getUris()
					.stream()
					.anyMatch(uri -> PARSER.parse(uri).matches(request.getPath().pathWithinApplication())));
			if (isAllowURI || isRequestHeaderValid(request)) {
				return chain.filter(exchange);
			}
		}
		catch (Exception ex) {
			log.error("Unable to apply permission filter, message {}", ex.getMessage());
		}
		return setUnauthorizedResponse(exchange);
	}

	private boolean isRequestHeaderValid(ServerHttpRequest request) {
		try {
			String securityContextHeader = request.getHeaders().get("X-SPD-Security-Context").get(0);
			SecurityContextHeader.UserProfile userProfile = UserUtil.getUserProfile(securityContextHeader);
			SecurityContextHeader.Edge ubmEdge = userProfile.getUserAccesses()
				.getEdges()
				.stream()
				.filter(edge -> edge.getNode().getResourceID().contains("/ubm"))
				.findFirst()
				.orElse(null);
			return ubmEdge != null && ubmEdge.getNode()
				.getPermissions()
				.stream()
				.map(Permission::fromValue)
				.anyMatch(p -> p != null && p.permissionMatches(request));
		}
		catch (ArrayIndexOutOfBoundsException | NullPointerException | JacksonException ex) {
			log.error("Failed to get permission from X-SPD-Security-Context header, message {}", ex.getMessage());
			throw new ServerException("Failed to get permission from X-SPD-Security-Context header");
		}

	}

	private Mono<Void> setUnauthorizedResponse(ServerWebExchange exchange) {
		ServerHttpResponse response = exchange.getResponse();
		response.setStatusCode(HttpStatus.FORBIDDEN);
		return response.setComplete();
	}

}

