package io.spdigital.ubm.logging;

import lombok.experimental.UtilityClass;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;

import java.util.Arrays;
import java.util.stream.Collectors;

@Slf4j
@UtilityClass
public class LogMasking {

	public static final String NULL = "<null>";

	public String maskName(String name) {
		name = StringUtils.normalizeSpace(name);
		return StringUtils.isBlank(name) ? NULL
				: (String) Arrays.asList(name.split("\\s"))
					.stream()
					.map(n -> maskText(n, 1, n.length()))
					.collect(Collectors.joining(" "));
	}

	public String maskPhone(String phoneNo) {
		return StringUtils.isEmpty(phoneNo) ? NULL : phoneNo.replaceAll("\\b(\\d{2})\\d+(\\d)", "$1*****$2");
	}

	public String maskEmail(String email) {
		return StringUtils.isEmpty(email) ? NULL : email.replaceAll("\\b(\\w)[^@]+@\\S+(\\.[^\\s.]+)", "$1*@***$2");
	}

	public String maskNricOrUen(String text) {
		return maskAndRetain(text, "*", 4);
	}

	public String maskAndRetain(String subject, String charReplacement, int lastCharsToRetain) {
		return null != subject && !"".equals(subject.trim())
				? subject.replaceAll(".(?=.{" + lastCharsToRetain + ",}$)", charReplacement) : "";
	}

	public String maskText(String text, int fromIndex, int toIndex) {
		char[] chars = text.toCharArray();
		Arrays.fill(chars, fromIndex, toIndex, '*');
		return new String(chars);
	}

}

