					"userId: " + userId));
	}

	public Mono<UtilityAccountDetail> getUtilityAccDetails(String bpNo, Yggdrasil.User.BPMapping bpMapping) {
		// retrieve system type
		return Mono.just(bpMapping)
			.filter(system -> bpMapping.getSystem().equals(System.MSSL.getSymbol()))
			// if MSSL then retrieve via corresponding ebs accNo in MSSL response
			.flatMap(mssl -> sapService
				.reactivePost(SAP.MSSL_CUSTOMER_DETAILS_RETRIEVAL, SAP.Request.builder().bpNo(bpNo).build(),
						MsslResponse.class)
				.map(MsslResponse::getHolder)
				.flatMap(msslBpItems -> {
					if (msslBpItems.getBpItems() != null && !msslBpItems.getBpItems().isEmpty()) {
						return Mono.just(msslBpItems.getBpItems().get(0));
					}
					else {
						return Mono.empty();
					}
				})
				.flatMap(msslBpItem -> sapService
					.reactivePost(SAP.EBS_CUSTOMER_DETAILS_RETRIEVAL, SAP.withAccountNo(msslBpItem.getEbsAccountNo()),
							SAP.EbsResponse.class)
					.map(SAP.EbsResponse::getDetailsHolder)
					.flatMap(AdminServiceImpl::getBpItem)))
			// if EBS then retrieve data from SAP immediately
			.switchIfEmpty(sapService.reactivePost(SAP.CUSTOMER_PROFILE_RETRIEVAL,
					SAP.RequestOld.builder().bpNo(bpNo).build(), SAP.EbsResponse.BpItem.class))
			.flatMap(ebsBpItem -> reactiveConnector
				.reactivePost(YGGDRASIL, GET_USER_BY_BP_NO,
						Yggdrasil.User.Request.builder()
							.bpNos(List.of(ebsBpItem.getBpNo() != null ? ebsBpItem.getBpNo() : bpNo))
							.build(),
						Yggdrasil.User.YD.Detail[].class)
				.map(userArray -> {
					Optional<Yggdrasil.User.YD.Detail> targetUser = Arrays.stream(userArray)
						.filter(u -> u.getEmail() != null && u.getEmail().equals(ebsBpItem.getEmailAddress()))
						.findFirst();

					String profileMobile = targetUser.map(Yggdrasil.User.YD.Detail::getMobile)
						.filter(m -> !m.isEmpty())
						.orElse(ebsBpItem.getMobileNo());
					return buildUtilityAccountDetail(ebsBpItem, profileMobile);
				})
				.switchIfEmpty(Mono.fromSupplier(() -> buildUtilityAccountDetail(ebsBpItem, ebsBpItem.getMobileNo()))))
			.switchIfEmpty(Mono.just(UtilityAccountDetail.builder().build()))
			.doOnError(throwable -> log.error(ERROR_OCCURRED, throwable.getMessage()))
			.onErrorResume(ex -> Mono
				.error(new UbmApiException(GENERIC_ERROR_MSG, GENERIC_ERROR_CODE, String.format("BpNo :%s", bpNo))));
	}

	private UtilityAccountDetail buildUtilityAccountDetail(SAP.EbsResponse.BpItem ebsBpItem, String mobile) {
		return UtilityAccountDetail.builder()
			.bpName(ebsBpItem.getBpName())
			.premiseAddress(ebsBpItem.getPremiseAddress())
			.emailSAP(ebsBpItem.getEmailAddress())
			.mobile(mobile)
			.phone(ebsBpItem.getPhone())
			.build();
	}

	private static Mono<SAP.EbsResponse.BpItem> getBpItem(SAP.EbsResponse.DetailsHolder bpItems) {
		if (bpItems.getBpItems() != null && !bpItems.getBpItems().isEmpty()) {
			return Mono.just(bpItems.getBpItems().get(0));
		}
		else {
			return Mono.empty();
		}
	}

