import io.spdigital.ubm.data.jpa.entity.NotificationBannerEntity;
import io.spdigital.ubm.data.jpa.repository.NotificationBannerRepository;
import io.spdigital.ubm.exception.ServerException;
import io.spdigital.ubm.exception.UbmApiException;
import io.spdigital.ubm.model.dto.BaseResponse;
import io.spdigital.ubm.service.notifications.dto.Notifications;
import io.spdigital.ubm.service.notifications.dto.Notifications.NotificationBanner;
import io.spdigital.ubm.service.notifications.enums.NotificationBannerLocationEnum;
import io.spdigital.ubm.service.notifications.enums.NotificationBannerPortalEnum;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.dao.EmptyResultDataAccessException;
import org.springframework.stereotype.Service;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Objects;
import java.util.Optional;
import java.util.stream.Collectors;

import static io.spdigital.ubm.modification.common.ErrorCodes.UBM_MODIFICATION_CREATE_NOTIFICATION_ERROR_CODE;
import static io.spdigital.ubm.modification.common.ErrorCodes.UBM_MODIFICATION_UPDATE_NOTIFICATION_ERROR_CODE;

@Slf4j
@Service
@RequiredArgsConstructor
public class NotificationBannersServiceImpl implements NotificationBannersService {

	public static final String DATE_RANGE_AND_LOCATION_MSG = "There is already an active banner for that date range and location.";

	private final NotificationBannerRepository repository;

	@Override
	public BaseResponse createNotificationBanner(Notifications.NotificationBannerRequest request) {
		log.info("Create Notification Banner Start");
		// Check if incoming notification banner is active
		if (request.isActive()) {
			// Check if still available
			List<NotificationBannerEntity> notificationBanners;
			if (request.getPortal() == null) {
				notificationBanners = repository.findAllByLocationDateOverlapping(request.getLocation(),
						request.getStartDateTime(), request.getEndDateTime());
			}
			else {
				notificationBanners = repository.findAllByLocationAndPortalDateOverlapping(request.getLocation(),
						request.getPortal(), request.getStartDateTime(), request.getEndDateTime());
			}

			if (!notificationBanners.isEmpty()) {
				log.error(DATE_RANGE_AND_LOCATION_MSG);
				throw new UbmApiException(DATE_RANGE_AND_LOCATION_MSG, UBM_MODIFICATION_CREATE_NOTIFICATION_ERROR_CODE,
						"Date range overlapping");
			}
		}
		NotificationBannerEntity notificationBanner = NotificationBannerEntity.from(request);
		notificationBanner.setCreatedDateTime(LocalDateTime.now());
		notificationBanner.setUpdatedDateTime(null);
		repository.save(notificationBanner);
		log.info("Create Notification Banner End");
		return BaseResponse.success();
	}

	@Override
	public List<Notifications.NotificationBanner> getNotificationBanners(Boolean oemOnly, Boolean uPortalOnly,
			NotificationBannerPortalEnum portal) {
		log.info("Get NotificationBanners Start");
		List<NotificationBannerEntity> notificationBanners;
		if (Boolean.TRUE.equals(oemOnly)) {
			notificationBanners = repository.findAllOEMOnly();
		}
		else if (Boolean.TRUE.equals(uPortalOnly)) {
			notificationBanners = repository.findAllUPortalOnly();
		}
		else if (Objects.nonNull(portal)) {
			notificationBanners = repository.findByPortal(portal);
		}
		else {
			notificationBanners = repository.findAll();
		}

		log.info("Get NotificationBanners End");
		return notificationBanners.stream().map(Notifications.NotificationBanner::from).toList();
	}

	@Override
	public BaseResponse updateNotificationBanner(Long id, Notifications.NotificationBannerRequest request) {
		log.info("Update NotificationBanner Start");
		Optional<NotificationBannerEntity> entityOptional = repository.findById(id);
		if (!entityOptional.isPresent()) {
			log.error("Update NotificationBanner Failed, ID {} not found", id);
			throw new ServerException("Update NotificationBanner Failed");
		}
		// Check if incoming notification banner is active
		if (request.isActive()) {
			// Check if still available
			List<NotificationBannerEntity> notificationBanners;
			if (request.getPortal() == null) {
				notificationBanners = repository.findAllByLocationDateOverlapping(request.getLocation(),
						request.getStartDateTime(), request.getEndDateTime());
			}
			else {
				notificationBanners = repository.findAllByLocationAndPortalDateOverlapping(request.getLocation(),
						request.getPortal(), request.getStartDateTime(), request.getEndDateTime());
			}
			if (!notificationBanners.isEmpty() && notificationBanners.stream().anyMatch(no -> no.getId() != id)) {
				log.error(DATE_RANGE_AND_LOCATION_MSG);
				throw new UbmApiException(DATE_RANGE_AND_LOCATION_MSG, UBM_MODIFICATION_UPDATE_NOTIFICATION_ERROR_CODE,
						"Date range overlapping");
			}

		}
		repository.save(updateEntity(request, entityOptional.get()));
		log.info("Update NotificationBanner End");
		return BaseResponse.success();
	}

	@Override
	public BaseResponse deleteNotificationBanner(Long id) {
		log.info("Delete NotificationBanner Start");
		try {
			repository.deleteById(id);
		}
		catch (EmptyResultDataAccessException e) {
			log.error("Delete NotificationBanner Failed ID Not , message {}", e.getMessage());
			throw new ServerException("Delete NotificationBanner Failed ID Not Found");
		}
		log.info("Delete NotificationBanner End");
		return BaseResponse.success();
	}

	private NotificationBannerEntity updateEntity(Notifications.NotificationBannerRequest request,
			NotificationBannerEntity entity) {
		entity.setTitle(request.getTitle());
		entity.setMessage(request.getMessage());
		entity.setStartDateTime(request.getStartDateTime());
		entity.setEndDateTime(request.getEndDateTime());
		entity.setLocation(request.getLocation());
		entity.setType(request.getType());
		entity.setActive(request.isActive());
		entity.setUpdatedBy(request.getUpdatedBy());
		entity.setUpdatedDateTime(LocalDateTime.now());
		entity.setPortal(request.getPortal());
		return entity;
	}

	@Override
	public List<Notifications.NotificationBanner> getNotificationBannersFromLocationAndPortal(
			NotificationBannerLocationEnum location, NotificationBannerPortalEnum portal) {
		log.info("Get NotificationBanners by location-{} and portal-{} Start", location, portal);
		LocalDateTime today = LocalDateTime.now();
		List<NotificationBannerEntity> notificationBanners = repository.findAllByLocationAndPortalDate(location, portal,
				today, today);
		log.info("Get NotificationBanners by location-{} and portal-{} End :: Found {} banners", location, portal,
				notificationBanners.size());
		return notificationBanners.stream().map(Notifications.NotificationBanner::from).collect(Collectors.toList());
	}

	@Override
	public Notifications.NotificationBanner getNotificationBannerById(Long id) {
		log.info("Get Notification Banner by ID {} Start", id);
		Optional<NotificationBannerEntity> entityOptional = repository.findById(id);
		if (!entityOptional.isPresent()) {
			log.error("Get Notification Banner Failed, ID {} not found", id);
			throw new ServerException("Get Notification Banner Failed");
		}

		log.info("Get Notification Banner by ID {} End", id);
		return Notifications.NotificationBanner.from(entityOptional.get());
	}

	@Override
	public List<Notifications.NotificationBanner> listUserNotificationBanners(String name) {
		log.info("listUserNotificationBanners :: Start - name {}", name);

		List<NotificationBannerEntity> notificationBanners = repository.findByCreatedBy(name);

		log.info("listUserNotificationBanners :: End - name {}", name);
		return notificationBanners.stream().map(Notifications.NotificationBanner::from).collect(Collectors.toList());
	}

	@Override
	public Notifications.NotificationBanner getBannerFromLocation(NotificationBannerLocationEnum location) {
		log.info("getBannerFromLocation :: Start");
		LocalDateTime today = LocalDateTime.now();
		List<NotificationBannerEntity> notificationBanners = repository.findAllByLocationDate(location, today, today);

		if (notificationBanners.isEmpty()) {
			log.info("getBannerFromLocation :: End :: Not found");
			return new Notifications.NotificationBanner();
		}
		log.info("getBannerFromLocation :: End :: Found {} banners", notificationBanners.size());
		return Notifications.NotificationBanner.from(notificationBanners.get(0));
	}

	@Override
	public List<Notifications.NotificationBanner> listAllActiveNotificationBanners() {
		log.info("listAllActiveNotificationBanners :: Start");
		LocalDateTime today = LocalDateTime.now();
		List<NotificationBannerEntity> notificationBanners = repository.findAllActive(today, today);

		log.info("listAllActiveNotificationBanners :: End");
		return notificationBanners.stream().map(Notifications.NotificationBanner::from).collect(Collectors.toList());
	}

}

