package io.spdigital.ubm.service.audit;

import static io.spdigital.ubm.config.ConnectionProperties.Host.AUDIT;
import static io.spdigital.ubm.service.audit.dto.Audit.AUDIT_ENDPOINT;
import static io.spdigital.ubm.util.Constants.FAIL;
import com.google.gson.Gson;
import io.spdigital.ubm.config.connector.ReactiveConnector;
import io.spdigital.ubm.service.audit.dto.Audit;
import io.spdigital.ubm.service.audit.dto.Audit.Get.Response;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import reactor.core.publisher.Mono;

@Slf4j
@Service
@RequiredArgsConstructor
public class AuditServiceImpl implements AuditService {

	public static final String CONDITIONS = "conditions";

	public static final String OCCURRED_IN_AUDIT_SERVICE = "#getAudit : {} :: Error occurred in Audit-Service : {}";

	private final ReactiveConnector reactiveConnector;

	@Override
	public Mono<String> createAudit(String service, String source, Object req, Object resp, String createdBy,
			String remarks) {
		Audit.Create.RequestParam auditTrailReq = Audit.Create.RequestParam.builder()
			.event(service)
			.source(source)
			.request(new Gson().toJson(req))
			.response(new Gson().toJson(resp))
			.createdBy(createdBy)
			.remarks(remarks)
			.build();
		return Mono.just(auditTrailReq)
			.flatMap(auditTrail -> reactiveConnector.reactivePost(AUDIT, AUDIT_ENDPOINT, auditTrail, String.class)
				.doOnError(throwable -> log.error("#createAudit : {} :: Error occurred in Auditservice : {}",
						auditTrail, throwable.getMessage()))
				.onErrorResume(throwable -> Mono.just(FAIL)));
	}

	@Override
	public Mono<Audit.Get.Response> getAudit(List<String> data, List<String> conditions, Integer pageNumber,
			Integer pageSize, String direction, String fromDate, String toDate) {
		return reactiveConnector
			.reactiveGet(AUDIT, AUDIT_ENDPOINT,
					Map.of("data", data, CONDITIONS, conditions, "pageNumber", List.of(pageNumber.toString()),
							"pageSize", List.of(pageSize.toString()), "direction", List.of(direction), "fromDate",
							List.of(fromDate), "toDate", List.of(toDate)),
					Collections.emptyMap(), Audit.Get.Response.class)
			.doOnError(throwable -> log.error(OCCURRED_IN_AUDIT_SERVICE, data, throwable.getMessage()))
			.onErrorResume(throwable -> Mono.just(Audit.Get.Response.builder().build()));
	}

	@Override
	public Mono<Response> getAudit(List<String> data, List<String> conditions, String fromDate, String toDate) {
		return reactiveConnector
			.reactiveGet(AUDIT, AUDIT_ENDPOINT,
					Map.of("data", data, CONDITIONS, conditions, "fromDate", List.of(fromDate), "toDate",
							List.of(toDate)),
					Collections.emptyMap(), Audit.Get.Response.class)
			.doOnError(throwable -> log.error(OCCURRED_IN_AUDIT_SERVICE, data, throwable.getMessage()))
			.onErrorResume(throwable -> Mono.just(Audit.Get.Response.builder().build()));
	}

	@Override
	public Mono<Response> getAdminAuditTrail(String data, List<String> conditions, Integer pageNumber, Integer pageSize,
			String direction, String createdBy, String remarks, String source) {
		return reactiveConnector
			.reactiveGet(AUDIT, AUDIT_ENDPOINT,
					Map.of("data", List.of(data), CONDITIONS, conditions, "pageNumber", List.of(pageNumber.toString()),
							"pageSize", List.of(pageSize.toString()), "direction", List.of(direction), "createdBy",
							List.of(createdBy), "remarks", List.of(remarks), "sources", List.of(source)),
					Collections.emptyMap(), Audit.Get.Response.class)
			.doOnError(throwable -> log.error(OCCURRED_IN_AUDIT_SERVICE, data, throwable.getMessage()))
			.onErrorResume(throwable -> Mono.just(Audit.Get.Response.builder().build()));
