package io.spdigital.ubm.common.enums;

import static java.util.Arrays.asList;

import java.util.Arrays;
import java.util.List;
import java.util.Optional;

public enum Utility {

	ELECTRICITY("01", "08"),

	GAS("02"),

	WATER("03"),

	UNKNOWN("")

	;

	public static Optional<Utility> parse(String sapVal) {
		return Arrays.stream(Utility.values()).filter(utility -> utility.getSapValues().contains(sapVal)).findFirst();
	}

	private List<String> sapValues;

	Utility(String... sapValues) {
		this.sapValues = asList(sapValues);
	}

	public String getSapValue() {
		return sapValues.get(0);
	}

	public List<String> getSapValues() {
		return sapValues;
	}

}

package io.spdigital.ubm.config;

import com.auth0.client.HttpOptions;
import com.auth0.client.ProxyOptions;
import com.auth0.client.auth.AuthAPI;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.net.InetSocketAddress;
import java.net.Proxy;

@Slf4j
@Configuration
@RequiredArgsConstructor
public class Auth0Configuration {

	private final SecurityProperties secProps;

	@Bean
	public Proxy proxy(ProxyProperties props) {
		return new Proxy(Proxy.Type.HTTP, new InetSocketAddress(props.getHost(), Integer.parseInt(props.getPort())));
	}

	@Bean
	public AuthAPI authAPI(Proxy proxy) {
		HttpOptions httpOptions = new HttpOptions();
		httpOptions.setProxyOptions(new ProxyOptions(proxy));
		log.info("iss:" + secProps.getIssuerUri() + ", clientId:" + secProps.getClientId());
		return new AuthAPI(secProps.getIssuerUri(), secProps.getClientId(), secProps.getClientSecret(), httpOptions);
	}

}

package io.spdigital.ubm.config;

import io.netty.handler.ssl.SslContext;
import io.netty.handler.ssl.SslContextBuilder;
import io.netty.handler.ssl.util.InsecureTrustManagerFactory;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.client.reactive.ReactorClientHttpConnector;
import org.springframework.web.reactive.config.EnableWebFlux;
import org.springframework.web.reactive.function.client.ExchangeFilterFunction;
import org.springframework.web.reactive.function.client.WebClient;
import reactor.core.publisher.Mono;
import reactor.netty.http.client.HttpClient;
import reactor.netty.transport.ProxyProvider;
import javax.net.ssl.SSLException;
import java.time.Duration;

@Slf4j
@Configuration
@EnableWebFlux
@RequiredArgsConstructor
public class WebClientConfiguration {

	private static final int CODEC_20_MB_SIZE = 20 * 1024 * 1024;

	private final ProxyProperties proxyProps;

	@Bean
	public WebClient.Builder webClientBuilder(SslContext sslContext) {
		HttpClient httpClient = HttpClient.create()
			.wiretap(true)
			.proxy(proxy -> proxy.type(ProxyProvider.Proxy.HTTP)
				.host(proxyProps.getHost())
				.port(Integer.parseInt(proxyProps.getPort()))
				.nonProxyHosts(proxyProps.getBypass()))
			.secure(t -> t.sslContext(sslContext).handshakeTimeout(Duration.ofMinutes(1)));
		return WebClient.builder()
			.codecs(clientCodecConfigurer -> clientCodecConfigurer.defaultCodecs().maxInMemorySize(CODEC_20_MB_SIZE))
			.clientConnector(new ReactorClientHttpConnector(httpClient));
	}

	@Bean
	public WebClient webClient(WebClient.Builder builder) {
		return builder.filters(functions -> {
			functions.add(logRequest());
			functions.add(logResponse());
		}).build();
	}

	private ExchangeFilterFunction logRequest() {
		return ExchangeFilterFunction.ofRequestProcessor(req -> {
			StringBuilder msg = new StringBuilder("Request:\n");
			req.headers().forEach((key, val) -> msg.append(key + ": " + val + "\n"));
			log.debug(msg.toString());
			return Mono.just(req);
		});
	}

	private ExchangeFilterFunction logResponse() {
		return ExchangeFilterFunction.ofResponseProcessor(res -> {
			StringBuilder msg = new StringBuilder("Response:\n");
			res.headers().asHttpHeaders().forEach((key, val) -> msg.append(key + ": " + val + "\n"));
			log.debug(msg.toString());
			return Mono.just(res);
		});
	}

	@Configuration
	public static class SSLConfiguration {

		@Bean
		public SslContext sslContext() throws SSLException {
			return SslContextBuilder.forClient().trustManager(InsecureTrustManagerFactory.INSTANCE).build();
		}

	}

}

