package io.spdigital.ubm.util;

import jakarta.xml.bind.DatatypeConverter;
import lombok.extern.slf4j.Slf4j;
import org.springframework.core.io.buffer.DataBufferUtils;
import org.springframework.http.codec.multipart.FilePart;
import org.springframework.stereotype.Component;
import reactor.core.publisher.Mono;

import java.nio.charset.StandardCharsets;

@Slf4j
@Component
public class FileUtil {

	public Mono<String> getFileByteArray(FilePart filePart) {

		return DataBufferUtils.join(filePart.content()).map(dataBuffer -> {
			byte[] bytes = new byte[dataBuffer.readableByteCount()];
			dataBuffer.read(bytes);
			DataBufferUtils.release(dataBuffer);
			return bytes;
		}).map(DatatypeConverter::printBase64Binary);
	}

	public Mono<String> getFileToString(FilePart filePart) {
		return DataBufferUtils.join(filePart.content()).map(dataBuffer -> {
			byte[] bytes = new byte[dataBuffer.readableByteCount()];
			dataBuffer.read(bytes);
			DataBufferUtils.release(dataBuffer);
			return bytes;
		}).map(bytes -> new String(bytes, StandardCharsets.UTF_8));
	}

}

package io.spdigital.ubm.config;

import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.reactive.EnableWebFluxSecurity;
import org.springframework.security.config.web.server.SecurityWebFiltersOrder;
import org.springframework.security.config.web.server.ServerHttpSecurity;
import org.springframework.security.web.server.SecurityWebFilterChain;

@Slf4j
@Configuration
@EnableWebFluxSecurity
@RequiredArgsConstructor
public class SecurityConfiguration {

	private final PermissionFilter permissionFilter;

	@Bean
	public SecurityWebFilterChain securityWebFilterChain(ServerHttpSecurity http) {
		http.csrf(ServerHttpSecurity.CsrfSpec::disable)
			.formLogin(ServerHttpSecurity.FormLoginSpec::disable)
			.httpBasic(ServerHttpSecurity.HttpBasicSpec::disable)
			.authorizeExchange(exchanges -> exchanges.anyExchange().permitAll())
			.addFilterAfter(permissionFilter, SecurityWebFiltersOrder.LAST);
		return http.build();
	}

}

package io.spdigital.ubm.logging;

import lombok.extern.slf4j.Slf4j;
import org.springframework.core.io.buffer.DataBuffer;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.http.server.reactive.ServerHttpRequestDecorator;
import reactor.core.publisher.Flux;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.nio.channels.Channels;
import java.nio.charset.StandardCharsets;

@Slf4j
public class RequestLoggingDecorator extends ServerHttpRequestDecorator {

	public RequestLoggingDecorator(ServerHttpRequest delegate) {
		super(delegate);
	}

	@Override
	public Flux<DataBuffer> getBody() {
		return super.getBody().map(dataBuffer -> {
			try (ByteArrayOutputStream baos = new ByteArrayOutputStream()) {
				Channels.newChannel(baos).write(dataBuffer.asByteBuffer().asReadOnlyBuffer());
				String body = new String(baos.toByteArray(), StandardCharsets.UTF_8);
				log.info("Request Payload:\n{}", body);
				return dataBuffer;
			}
			catch (IOException ex) {
				log.error("IO error while reading request body.", ex);
				return dataBuffer;
			}
		});
	}

}

package io.spdigital.ubm.web;

import io.spdigital.ubm.logging.RequestLoggingDecorator;
import io.spdigital.ubm.logging.ResponseLoggingDecorator;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.http.server.reactive.ServerHttpResponse;
import org.springframework.web.server.ServerWebExchange;
import org.springframework.web.server.ServerWebExchangeDecorator;
import org.springframework.web.server.WebFilter;
import org.springframework.web.server.WebFilterChain;
import reactor.core.publisher.Mono;

@Configuration
public class RequestLoggingFilter implements WebFilter {

	public Mono<Void> filter(ServerWebExchange exchange, WebFilterChain chain) {
		ServerWebExchangeDecorator decorator = new ServerWebExchangeDecorator(exchange) {

			@Override
			public ServerHttpRequest getRequest() {
				return new RequestLoggingDecorator(exchange.getRequest());
			}

			@Override
			public ServerHttpResponse getResponse() {
				return new ResponseLoggingDecorator(exchange.getResponse());
			}
		};
		return chain.filter(decorator);
	}

}

package io.spdigital.ubm.logging;

import lombok.experimental.UtilityClass;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;

import java.util.Arrays;
import java.util.stream.Collectors;

@Slf4j
@UtilityClass
public class LogMasking {

	public static final String NULL = "<null>";

	public String maskName(String name) {
		name = StringUtils.normalizeSpace(name);
		return StringUtils.isBlank(name) ? NULL
				: (String) Arrays.asList(name.split("\\s"))
					.stream()
					.map(n -> maskText(n, 1, n.length()))
					.collect(Collectors.joining(" "));
	}

	public String maskPhone(String phoneNo) {
		return StringUtils.isEmpty(phoneNo) ? NULL : phoneNo.replaceAll("\\b(\\d{2})\\d+(\\d)", "$1*****$2");
	}

	public String maskEmail(String email) {
		return StringUtils.isEmpty(email) ? NULL : email.replaceAll("\\b(\\w)[^@]+@\\S+(\\.[^\\s.]+)", "$1*@***$2");
	}

	public String maskNricOrUen(String text) {
		return maskAndRetain(text, "*", 4);
	}

	public String maskAndRetain(String subject, String charReplacement, int lastCharsToRetain) {
		return null != subject && !"".equals(subject.trim())
				? subject.replaceAll(".(?=.{" + lastCharsToRetain + ",}$)", charReplacement) : "";
	}

	public String maskText(String text, int fromIndex, int toIndex) {
		char[] chars = text.toCharArray();
		Arrays.fill(chars, fromIndex, toIndex, '*');
		return new String(chars);
	}

}

package io.spdigital.ubm.util;

import static org.apache.commons.lang3.StringUtils.isBlank;

import java.util.Arrays;
import java.util.stream.Collectors;

import lombok.experimental.UtilityClass;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;

@Slf4j
@UtilityClass
public class MaskingUtil {

	public static final String NULL = "<null>";

	public String maskName(String name) {
		return isBlank(name) ? "<null>"
				: (String) Arrays.asList(name.trim().split("\\s+"))
					.stream()
					.map((n) -> maskText(n, 1, n.length()))
					.collect(Collectors.joining(" "));
	}

	public String maskPhone(String phoneNo) {
		return StringUtils.isEmpty(phoneNo) ? NULL : phoneNo.replaceAll("\\b(\\d{2})\\d+(\\d)", "$1*****$2");
	}

	public String maskEmail(String email) {
		return StringUtils.isEmpty(email) ? NULL : email.replaceAll("\\b(\\w)[^@]+@\\S+(\\.[^\\s.]+)", "$1*@***$2");
	}

	public String maskNricOrUen(String text) {
		return maskAndRetain(text, "*", 4);
	}

	public String maskAndRetain(String subject, String charReplacement, int lastCharsToRetain) {
		return null != subject && !"".equals(subject.trim())
				? subject.replaceAll(".(?=.{" + lastCharsToRetain + ",}$)", charReplacement) : "";
	}

	public String maskText(String text, int fromIndex, int toIndex) {
		char[] chars = text.toCharArray();
		Arrays.fill(chars, fromIndex, toIndex, '*');
		return new String(chars);
	}

}

package io.spdigital.ubm.util;

import org.springframework.stereotype.Component;

import java.util.function.Predicate;

@Component
public class AccountUtility {

	public static final String ACCOUNT_NO_PREFIX = "00";

	public static final Integer ACCOUNT_NO_LENGTH_10 = 10;

	public static final Integer ACCOUNT_NO_LENGTH_12 = 12;

	public static final String ACCOUNT_NO_MSSL = "93";

	public static final String hyphen = "-";

	public static final Predicate<String> isMSSLAccountCheck = accNo -> (accNo.length() == 10 && accNo.startsWith("93"))
			|| (accNo.length() == 12 && accNo.startsWith("0093"));

	public String prefixAccountNo(String accountNo) {
		return prefixAccountNoFn(accountNo);
	}

	public static String prefixAccountNoFn(String accountNo) {
		if (null != accountNo && accountNo.length() == ACCOUNT_NO_LENGTH_10 && !accountNo.startsWith(ACCOUNT_NO_PREFIX)
				&& !hyphen.equals(accountNo.substring(accountNo.length() - 1))) {
			accountNo = ACCOUNT_NO_PREFIX + accountNo;
		}
		return accountNo;
	}

	public String deprefixAccountNo(String accountNo) {
		return deprefixAccountNoFn(accountNo);
	}

	public static String deprefixAccountNoFn(String accountNo) {
		if (null != accountNo && accountNo.length() == ACCOUNT_NO_LENGTH_12
				&& accountNo.startsWith(ACCOUNT_NO_PREFIX)) {
			accountNo = accountNo.substring(ACCOUNT_NO_PREFIX.length());
		}
		return accountNo;
	}

	/**
	 * Check account no prefix is MSSL or not param account no nullable
	 */
	public static Boolean checkIsMSSLAccount(String accountNo) {
		return isMSSLAccountCheck.test(accountNo);
	}

}

package io.spdigital.ubm.logging;

import lombok.extern.slf4j.Slf4j;
import org.reactivestreams.Publisher;
import org.springframework.core.io.buffer.DataBuffer;
import org.springframework.core.io.buffer.DataBufferUtils;
import org.springframework.http.server.reactive.ServerHttpResponse;
import org.springframework.http.server.reactive.ServerHttpResponseDecorator;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;

import java.nio.charset.StandardCharsets;

@Slf4j
public class ResponseLoggingDecorator extends ServerHttpResponseDecorator {

	public ResponseLoggingDecorator(ServerHttpResponse delegate) {
		super(delegate);
	}

	@Override
	public Mono<Void> writeWith(Publisher<? extends DataBuffer> body) {
		if (body instanceof Flux) {
			Flux<? extends DataBuffer> fluxBody = (Flux<? extends DataBuffer>) body;
			return super.writeWith(fluxBody.map(dataBuffer -> {
				byte[] content = new byte[dataBuffer.readableByteCount()];
				dataBuffer.read(content);
				String response = new String(content, StandardCharsets.UTF_8);
				if (response.startsWith("{\"status\":"))
					log.info("Flux Response: {}", response);
				DataBufferUtils.release(dataBuffer);
				return super.bufferFactory().wrap(content);
			}));
		}
		else if (body instanceof Mono) {
			Mono<? extends DataBuffer> monoBody = (Mono<? extends DataBuffer>) body;
			return super.writeWith(monoBody.map(dataBuffer -> {
				byte[] content = new byte[dataBuffer.readableByteCount()];
				dataBuffer.read(content);
				String response = new String(content, StandardCharsets.UTF_8);
				if (response.startsWith("{\"status\":"))
					log.info("Mono Response: {}", response);
				DataBufferUtils.release(dataBuffer);
				return super.bufferFactory().wrap(content);
			}));
		}
		else {
			String className = (body != null) ? body.getClass().getName() : "null";
			log.debug("ResponseLoggingDecorator :: class:{}", className);
		}
		return super.writeWith(body);
	}

}

